// BiometricAuthManager.java
package com.example.biometricauth;

import android.content.Context;
import android.content.SharedPreferences;
import android.os.Build;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import android.util.Log;

import androidx.annotation.NonNull;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;
import androidx.fragment.app.FragmentActivity;

import java.security.KeyStore;
import java.util.concurrent.Executor;

import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;

public class BiometricAuthManager {

    private static final String TAG = "BiometricAuthManager";
    private static final String PREFS_NAME = "biometric_prefs";
    private static final String KEY_BIOMETRIC_ENABLED = "biometric_enabled";
    private static final String KEY_USER_AUTHENTICATED = "user_authenticated";
    private static final String KEY_USER_TOKEN = "user_token";
    private static final String KEYSTORE_ALIAS = "biometric_key";
    private static final String ANDROID_KEYSTORE = "AndroidKeyStore";

    private final Context context;
    private final SharedPreferences sharedPreferences;

    public interface BiometricAuthCallback {
        void onAuthenticationSucceeded();
        void onAuthenticationFailed();
        void onAuthenticationError(int errorCode, String errorMessage);
        void onBiometricNotAvailable(String reason);
    }

    public BiometricAuthManager(Context context) {
        this.context = context.getApplicationContext();
        this.sharedPreferences = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
    }

    public boolean isBiometricAvailable() {
        BiometricManager biometricManager = BiometricManager.from(context);
        int canAuthenticate = biometricManager.canAuthenticate(
                BiometricManager.Authenticators.BIOMETRIC_STRONG);
        return canAuthenticate == BiometricManager.BIOMETRIC_SUCCESS;
    }

    public int getBiometricAvailabilityStatus() {
        BiometricManager biometricManager = BiometricManager.from(context);
        return biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG);
    }

    public String getBiometricStatusMessage() {
        int status = getBiometricAvailabilityStatus();
        switch (status) {
            case BiometricManager.BIOMETRIC_SUCCESS:
                return "Biometric authentication is available.";
            case BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE:
                return "No biometric hardware available on this device.";
            case BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE:
                return "Biometric hardware is currently unavailable.";
            case BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED:
                return "No biometric credentials enrolled. Please set up fingerprint in device settings.";
            case BiometricManager.BIOMETRIC_ERROR_SECURITY_UPDATE_REQUIRED:
                return "A security update is required to use biometrics.";
            case BiometricManager.BIOMETRIC_ERROR_UNSUPPORTED:
                return "Biometric authentication is not supported.";
            case BiometricManager.BIOMETRIC_STATUS_UNKNOWN:
            default:
                return "Biometric status is unknown.";
        }
    }

    public void enableBiometricLogin(String userToken) {
        sharedPreferences.edit()
                .putBoolean(KEY_BIOMETRIC_ENABLED, true)
                .putString(KEY_USER_TOKEN, userToken)
                .apply();
        generateSecretKey();
        Log.d(TAG, "Biometric login enabled");
    }

    public void disableBiometricLogin() {
        sharedPreferences.edit()
                .putBoolean(KEY_BIOMETRIC_ENABLED, false)
                .remove(KEY_USER_TOKEN)
                .putBoolean(KEY_USER_AUTHENTICATED, false)
                .apply();
        deleteSecretKey();
        Log.d(TAG, "Biometric login disabled");
    }

    public boolean isBiometricLoginEnabled() {
        return sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false);
    }

    public boolean isUserAuthenticated() {
        return sharedPreferences.getBoolean(KEY_USER_AUTHENTICATED, false);
    }

    public void setUserAuthenticated(boolean authenticated) {
        sharedPreferences.edit()
                .putBoolean(KEY_USER_AUTHENTICATED, authenticated)
                .apply();
    }

    public String getUserToken() {
        return sharedPreferences.getString(KEY_USER_TOKEN, null);
    }

    public boolean shouldShowBiometricPrompt() {
        return isBiometricAvailable() && isBiometricLoginEnabled() && getUserToken() != null;
    }

    public void authenticate(@NonNull FragmentActivity activity,
                             @NonNull BiometricAuthCallback callback) {
        if (!isBiometricAvailable()) {
            callback.onBiometricNotAvailable(getBiometricStatusMessage());
            return;
        }

        Executor executor = ContextCompat.getMainExecutor(activity);

        BiometricPrompt.AuthenticationCallback authCallback =
                new BiometricPrompt.AuthenticationCallback() {
                    @Override
                    public void onAuthenticationSucceeded(
                            @NonNull BiometricPrompt.AuthenticationResult result) {
                        super.onAuthenticationSucceeded(result);
                        Log.d(TAG, "Authentication succeeded");
                        setUserAuthenticated(true);
                        callback.onAuthenticationSucceeded();
                    }

                    @Override
                    public void onAuthenticationFailed() {
                        super.onAuthenticationFailed();
                        Log.d(TAG, "Authentication failed");
                        callback.onAuthenticationFailed();
                    }

                    @Override
                    public void onAuthenticationError(int errorCode,
                                                      @NonNull CharSequence errString) {
                        super.onAuthenticationError(errorCode, errString);
                        Log.e(TAG, "Authentication error: " + errString);
                        callback.onAuthenticationError(errorCode, errString.toString());
                    }
                };

        BiometricPrompt biometricPrompt = new BiometricPrompt(activity, executor, authCallback);

        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Biometric Login")
                .setSubtitle("Use your fingerprint to log in")
                .setDescription("Place your finger on the sensor to authenticate")
                .setNegativeButtonText("Use Password")
                .setConfirmationRequired(false)
                .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG)
                .build();

        try {
            SecretKey secretKey = getSecretKey();
            if (secretKey != null) {
                Cipher cipher = getCipher();
                cipher.init(Cipher.ENCRYPT_MODE, secretKey);
                biometricPrompt.authenticate(promptInfo,
                        new BiometricPrompt.CryptoObject(cipher));
            } else {
                biometricPrompt.authenticate(promptInfo);
            }
        } catch (Exception e) {
            Log.w(TAG, "CryptoObject setup failed, authenticating without crypto", e);
            biometricPrompt.authenticate(promptInfo);
        }
    }

    public void authenticateForEnrollment(@NonNull FragmentActivity activity,
                                          @NonNull String userToken,
                                          @NonNull BiometricAuthCallback callback) {
        if (!isBiometricAvailable()) {
            callback.onBiometricNotAvailable(getBiometricStatusMessage());
            return;
        }

        Executor executor = ContextCompat.getMainExecutor(activity);

        BiometricPrompt.AuthenticationCallback authCallback =
                new BiometricPrompt.AuthenticationCallback() {
                    @Override
                    public void onAuthenticationSucceeded(
                            @NonNull BiometricPrompt.AuthenticationResult result) {
                        super.onAuthenticationSucceeded(result);
                        enableBiometricLogin(userToken);
                        setUserAuthenticated(true);
                        Log.d(TAG, "Enrollment authentication succeeded");
                        callback.onAuthenticationSucceeded();
                    }

                    @Override
                    public void onAuthenticationFailed() {
                        super.onAuthenticationFailed();
                        callback.onAuthenticationFailed();
                    }

                    @Override
                    public void onAuthenticationError(int errorCode,
                                                      @NonNull CharSequence errString) {
                        super.onAuthenticationError(errorCode, errString);
                        callback.onAuthenticationError(errorCode, errString.toString());
                    }
                };

        BiometricPrompt biometricPrompt = new BiometricPrompt(activity, executor, authCallback);

        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Enable Biometric Login")
                .setSubtitle("Verify your fingerprint to enable biometric login")
                .setDescription("This will allow you to log in using your fingerprint in the future")
                .setNegativeButtonText("Cancel")
                .setConfirmationRequired(true)
                .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG)
                .build();

        biometricPrompt.authenticate(promptInfo);
    }

    public void clearAuthenticationState() {
        setUserAuthenticated(false);
    }

    private void generateSecretKey() {
        try {
            KeyGenerator keyGenerator = KeyGenerator.getInstance(
                    KeyProperties.KEY_ALGORITHM_AES, ANDROID_KEYSTORE);

            KeyGenParameterSpec.Builder builder = new KeyGenParameterSpec.Builder(
                    KEYSTORE_ALIAS,
                    KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                    .setBlockModes(KeyProperties.BLOCK_MODE_CBC)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_PKCS7)
                    .setUserAuthenticationRequired(true);

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
                builder.setUserAuthenticationParameters(0,
                        KeyProperties.AUTH_BIOMETRIC_STRONG);
            } else {
                builder.setUserAuthenticationValidityDurationSeconds(-1);
            }

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                builder.setInvalidatedByBiometricEnrollment(true);
            }

            keyGenerator.init(builder.build());
            keyGenerator.generateKey();
            Log.d(TAG, "Secret key generated successfully");
        } catch (Exception e) {
            Log.e(TAG, "Error generating secret key", e);
        }
    }

    private SecretKey getSecretKey() {
        try {
            KeyStore keyStore = KeyStore.getInstance(ANDROID_KEYSTORE);
            keyStore.load(null);
            return (SecretKey) keyStore.getKey(KEYSTORE_ALIAS, null);
        } catch (Exception e) {
            Log.e(TAG, "Error getting secret key", e);
            return null;
        }
    }

    private Cipher getCipher() throws Exception {
        return Cipher.getInstance(
                KeyProperties.KEY_ALGORITHM_AES + "/"
                        + KeyProperties.BLOCK_MODE_CBC + "/"
                        + KeyProperties.ENCRYPTION_PADDING_PKCS7);
    }

    private void deleteSecretKey() {
        try {
            KeyStore keyStore = KeyStore.getInstance(ANDROID_KEYSTORE);
            keyStore.load(null);
            keyStore.deleteEntry(KEYSTORE_ALIAS);
            Log.d(TAG, "Secret key deleted");
        } catch (Exception e) {
            Log.e(TAG, "Error deleting secret key", e);
        }
    }
}